import threading

import gi
gi.require_version('Gtk', '3.0')  # @UndefinedVariable
from gi.repository import Gtk, GLib  # @UnresolvedImport

def add_idle_call(func, *args):
    source_id = GLib.idle_add(func, *args, priority=GLib.PRIORITY_HIGH_IDLE)
    if threading.current_thread() is threading.main_thread():
        # find_source_by_id is only safe to call from the main thread.
        return GLib.MainContext.default().find_source_by_id(source_id)
    else:
        # Called from a background thread (e.g. refinement): idle_add is
        # thread-safe and schedules the callback; we just can't cancel it.
        return None

def remove_source(source):
    if source is not None:
        return source.destroy()

def add_timeout_call(timeout, func, *args):
    source = GLib.MainContext.default().find_source_by_id(
        GLib.timeout_add(timeout, func, priority=GLib.PRIORITY_HIGH, *args))
    return source

def start_event_loop():
    return Gtk.main()

def stop_event_loop():
    return Gtk.main_quit()